3	const SURVIVAL_NEIGHBORS = 2;
4	const BIRTH_NEIGHBORS = 3;
5	
6	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
7	
8	const neighborOffsets: ReadonlyArray<Cell> = [
9	  [-1, -1], [-1, 0], [-1, 1],
10	  [0, -1],           [0, 1],
11	  [1, -1],  [1, 0],  [1, 1],
12	];
