17	  const tallies = new Map<string, NeighborTally>();
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of neighborOffsets) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const key = cellKey(neighbor);
22	      const tally = tallies.get(key) ?? { cell: neighbor, count: 0 };
23	      tally.count += 1;
24	      tallies.set(key, tally);
25	    }
26	  }
27	  return tallies;
28	}
29	
30	function isAliveNextGeneration(neighborCount: number, isAlive: boolean): boolean {
31	  if (neighborCount === BIRTH_NEIGHBORS) return true;
32	  return neighborCount === SURVIVAL_NEIGHBORS && isAlive;
33	}
34	
35	export function nextGeneration(cells: Cell[]): Cell[] {
36	  const alive = new Set(cells.map(cellKey));
37	  const tallies = tallyNeighbors(cells);
38	  const result: Cell[] = [];
39	  for (const [key, { cell, count }] of tallies) {
40	    if (isAliveNextGeneration(count, alive.has(key))) result.push(cell);
