4	describe("Game of Life - nextGeneration", () => {
5	  it("empty grid stays empty — []", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("single cell dies (underpopulation) — [(0,0)] → []", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("two adjacent cells both die (underpopulation, 1 neighbor each) — [(0,1), (1,1)] → []", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("block still life remains unchanged — [(0,0),(1,0),(0,1),(1,1)] → same", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result).toHaveLength(4);
18	    expect(result).toEqual(expect.arrayContaining(block));
19	  });
20	  it("live cell with >3 neighbors dies (overpopulation) — center of ### / .#. / ### dies", () => {
21	    const gen0: [number, number][] = [
22	      [0, 0], [1, 0], [2, 0],
23	              [1, 1],
24	      [0, 2], [1, 2], [2, 2],
25	    ];
26	    const result = nextGeneration(gen0);
27	    expect(result).not.toContainEqual([1, 1]);
28	  });
29	  it("dead cell with exactly 3 neighbors becomes alive (reproduction) — L-shape produces new cell at (1,1)", () => {
30	    const gen0: [number, number][] = [[0, 0], [1, 0], [0, 1]];
31	    const result = nextGeneration(gen0);
32	    expect(result).toContainEqual([1, 1]);
33	  });
34	  it("blinker oscillates from vertical to horizontal — [(0,0),(0,1),(0,2)] → [(-1,1),(0,1),(1,1)]", () => {
35	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
36	    const horizontal: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
37	    const result = nextGeneration(vertical);
38	    expect(result).toHaveLength(3);
39	    expect(result).toEqual(expect.arrayContaining(horizontal));
40	  });
